import { icons } from 'lucide-react'
import { Icon } from '../../shared/dynamic-icon/dynamic-icon'
import { cn } from '@/lib/utils'

export interface GridMediaCardsProps {
  title: string
  items: {
    title: string
    description: string
    icon: string
    image: {
      url: string
      alt: string
      overlay?: boolean
      whiteTexts?: boolean
    }
  }[]
}

export function GridMediaCards({
  title,
  items,
}: Readonly<GridMediaCardsProps>) {
  return (
    <div>
      <h2 className="mb-6 text-2xl font-bold">{title}</h2>
      <div className="grid grid-cols-1 gap-4 md:grid-cols-3">
        {items?.map((item, index) => (
          <div
            key={item.title + index}
            className="relative h-96 overflow-hidden rounded-lg"
          >
            <img
              src={item.image.url}
              alt={item.image.alt}
              loading="lazy"
              decoding="async"
              className="absolute inset-0 size-full object-cover"
            />
            {item.image.overlay && (
              <div className="absolute inset-0 bg-black/50" />
            )}
            <div
              className={cn(
                'absolute inset-0 flex flex-col justify-end p-6',
                item.image.whiteTexts && 'text-white',
              )}
            >
              {item.icon && (
                <Icon
                  name={item.icon as keyof typeof icons}
                  className="mb-2 size-5"
                />
              )}
              <h3 className="mb-1 text-lg font-medium">{item.title}</h3>
              {item.description && (
                <p className="text-sm">{item.description}</p>
              )}
            </div>
          </div>
        ))}
      </div>
    </div>
  )
}

import { GridMediaCards, type GridMediaCardsProps } from './grid-media-cards'

export const values = {
  title: 'Focus areas',
  items: [
    {
      title: 'Clean interfaces',
      description: 'Minimal layouts that put content first and noise last.',
      icon: 'Palette',
      image: {
        url: 'https://images.unsplash.com/photo-1770838917379-32208420ea9a?q=80&w=687&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D',
        alt: 'Clean workspace',
        whiteTexts: true,
      },
    },
    {
      title: 'Documentation',
      description:
        'Clear guides and examples so you can move fast without guessing.',
      icon: 'Code',
      image: {
        url: 'https://images.unsplash.com/photo-1756826513350-5b660cb91b55?q=80&w=687&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D',
        alt: 'Developer on laptop',
        whiteTexts: true,
      },
    },
    {
      title: 'Open by default',
      description:
        'Built in the open so you can adapt, extend, and own your stack.',
      icon: 'Users',
      image: {
        url: 'https://images.unsplash.com/photo-1658725935880-3b93d812d42c?q=80&w=1170&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D',
        alt: 'Team collaboration',
        whiteTexts: true,
      },
    },
  ],
} satisfies GridMediaCardsProps

export function GridMediaCardsExample() {
  return <GridMediaCards title={values.title} items={values.items} />
}
